// Tests for src/game/enemies.{h,cc}.
// Spec: docs/test-plan/02-test-specifications.md §9 (T-ENM-005..060).
//
// HP-roll tests use seeds pinned in tests/seeds/expected_values.h: the
// concrete 38..41 / 51..53 outcomes depend on the host STL's
// uniform_int_distribution implementation, so values are not portable
// across toolchains — they are regenerated by tools/seed-pinner. The
// fixed kCombatTestSeed is used wherever a Combat is constructed, in
// line with the broader test suite convention.

#include <gtest/gtest.h>

#include <vector>

#include "sts2/game/combat.h"
