using sts2::tests::seeds::kDampSeedHp52;
using sts2::tests::seeds::kDampSeedHp53;

TEST(EnemiesCultistArchetypeCatalog, LooksUpByWireName) {
  const auto* calcified =
      sts2::enemies::cultist_archetype_from_wire_name("CalcifiedCultist");
  ASSERT_NE(calcified, nullptr);
  EXPECT_EQ(calcified->internal_name, "Calcified Cultist");
  EXPECT_EQ(calcified->wire_name, "CalcifiedCultist");
  EXPECT_EQ(calcified->hp_min, 38);
  EXPECT_EQ(calcified->hp_max, 41);
  EXPECT_EQ(calcified->dark_strike_base, 9);
  EXPECT_EQ(calcified->ritual_amount, 2);

  const auto* damp =
      sts2::enemies::cultist_archetype_from_wire_name("DampCultist");
  ASSERT_NE(damp, nullptr);
  EXPECT_EQ(damp->internal_name, "Damp Cultist");
  EXPECT_EQ(damp->wire_name, "DampCultist");
  EXPECT_EQ(damp->hp_min, 51);
  EXPECT_EQ(damp->hp_max, 53);
  EXPECT_EQ(damp->dark_strike_base, 1);
  EXPECT_EQ(damp->ritual_amount, 5);
}

TEST(EnemiesCultistArchetypeCatalog, LooksUpByInternalName) {
  const auto* calcified =
      sts2::enemies::cultist_archetype_from_internal_name("Calcified Cultist");
  ASSERT_NE(calcified, nullptr);
  EXPECT_EQ(calcified->wire_name, "CalcifiedCultist");

  const auto* damp =
      sts2::enemies::cultist_archetype_from_internal_name("Damp Cultist");
  ASSERT_NE(damp, nullptr);
  EXPECT_EQ(damp->wire_name, "DampCultist");
}

TEST(EnemiesCultistArchetypeCatalog, UnknownNameReturnsNull) {
  EXPECT_EQ(sts2::enemies::cultist_archetype_from_wire_name("JawWorm"),
            nullptr);
  EXPECT_EQ(sts2::enemies::cultist_archetype_from_internal_name("Jaw Worm"),
            nullptr);
}

// -------------------------------------------------------------------------
// 9.1  enemies::make_calcified_cultist(Rng&)
// -------------------------------------------------------------------------

// T-ENM-005 — BP, BV — Stable cultist with kCultistTestSeed. Pins all
// constructor invariants plus the def-use chain hp → max_hp/hp.
TEST(EnemiesMakeCalcified, T_ENM_005_StableCultistAtSeed42) {
  Rng r{kCultistTestSeed};
  Enemy e = sts2::enemies::make_calcified_cultist(r);

  EXPECT_EQ(e.name, "Calcified Cultist");
  EXPECT_EQ(e.vitals.max_hp, e.vitals.hp);
  EXPECT_EQ(e.vitals.hp, Stat{kCalcifiedHpSeed42});
  EXPECT_GE(e.vitals.hp, Stat{38});
  EXPECT_LE(e.vitals.hp, Stat{41});
  EXPECT_EQ(e.dark_strike_base, Stat{9});
  EXPECT_EQ(e.ritual_amount, Stat{2});
  EXPECT_EQ(e.current_move, MoveId::kIncantation);
  EXPECT_FALSE(e.performed_first_move);
  EXPECT_EQ(e.vitals.block, Stat{0});
  EXPECT_TRUE(e.vitals.powers.empty());
  EXPECT_EQ(e.kind, sts2::game::MonsterKind::kCultistCalcified);
}

// T-ENM-010 — EG, BV — All four HP outcomes 38..41 reachable; locks the
// closed-interval contract on uniform_int and that the constructor does
// not clamp.
TEST(EnemiesMakeCalcified, T_ENM_010_AllHpOutcomesReachable) {
  {
    Rng r{kCalcifiedSeedHp38};
    Enemy e = sts2::enemies::make_calcified_cultist(r);
    EXPECT_EQ(e.vitals.hp, Stat{38});
  }
  {
    Rng r{kCalcifiedSeedHp39};
    Enemy e = sts2::enemies::make_calcified_cultist(r);
    EXPECT_EQ(e.vitals.hp, Stat{39});
  }
  {
    Rng r{kCalcifiedSeedHp40};
    Enemy e = sts2::enemies::make_calcified_cultist(r);
    EXPECT_EQ(e.vitals.hp, Stat{40});
  }
  {
    Rng r{kCalcifiedSeedHp41};
    Enemy e = sts2::enemies::make_calcified_cultist(r);
    EXPECT_EQ(e.vitals.hp, Stat{41});
  }
}

